function solve(nums: number[], queries: number[][]): number {
    const MOD = 10**9 + 7;
    const n = nums.length;

    // Initialize an array to keep track of the number of times each element is multiplied
    const multiplyCount = new Array(n).fill(0);

    // Process each query
    for (const [li, ri, ki, vi] of queries) {
        let idx = li;
        while (idx <= ri) {
            multiplyCount[idx] += 1;
            idx += ki;
        }
    }

    // Calculate the final value of each element and compute the XOR
    let xorResult = 0;
    for (let i = 0; i < n; i++) {
        let val = nums[i];
        for (let j = 0; j < multiplyCount[i]; j++) {
            val = (val * vi) % MOD;
        }
        xorResult ^= val;
    }

    return xorResult;
}

